import './TermsOfUse.css'; 

const TermsOfUsePage = () => {
  return (
    <>
      <Header />
      <main>
        <div className="container">
          <div className="text-content-page">
            <h1>Termos de Uso</h1>
            <p className="last-updated">Última atualização: 3 de Outubro de 2025</p>
            <h2>1. Aceitação dos Termos</h2>
            <p>Bem-vindo à <strong>Cortex Studio</strong>. Ao acessar e utilizar nosso website...</p>
            {/* Cole o resto do seu texto completo dos Termos de Uso aqui */}
          </div>
        </div>
      </main>
      <Footer />
    </>
  );
};

export default TermsOfUsePage;
